import os
import numpy as np

from mudlab.generic.io.utils import get_case_insensitive_glob
from mudlab.generic.utils import not_none

from ..base_parser import BaseParser
from ..xml_parser_mixin import XMLParserMixin
from .xrd_parser_mixin import XRDParserMixin
from .namespace import xrd_parsers

@xrd_parsers.register_parser()
class XRDMLParser(XRDParserMixin, XMLParserMixin, BaseParser):
    """
        PANalytical *.XRDML format parser.
        XRDML is an XML-based format used by PANalytical (Malvern PANalytical)
        XRD instruments. Intensities are normalised to counts-per-second on
        import.
    """

    description = "PANalytical XRDML files"
    extensions = get_case_insensitive_glob("*.XRDML")
    mimetypes = ["application/xml", "text/xml"]

    # ElementTree works fine with binary mode and handles XML encoding declarations
    __file_mode__ = "rb"

    # ------------------------------------------------------------------
    #   Namespace helpers
    # ------------------------------------------------------------------

    @classmethod
    def _ns(cls, tag, ns):
        return ('{%s}%s' % (ns, tag)) if ns else tag

    @classmethod
    def _get_ns(cls, root):
        """Extract the namespace URI from the root element tag."""
        tag = root.tag
        if tag.startswith('{'):
            return tag[1:tag.index('}')]
        return ''

    @classmethod
    def _find(cls, element, tag, ns):
        return element.find(cls._ns(tag, ns))

    @classmethod
    def _findall(cls, element, tag, ns):
        return element.findall(cls._ns(tag, ns))

    @classmethod
    def _iter(cls, element, tag, ns):
        return element.iter(cls._ns(tag, ns))

    @classmethod
    def _text(cls, element, tag, ns, default=None):
        el = cls._find(element, tag, ns)
        if el is not None and el.text:
            return el.text.strip()
        return default

    # ------------------------------------------------------------------
    #   Header / wavelength extraction
    # ------------------------------------------------------------------

    @classmethod
    def _parse_wavelength(cls, root, ns):
        """
        Return a dict with alpha1, alpha2, beta, alpha_average (all in nm).
        XRDML stores wavelengths in Angstroms; 1 Å = 0.1 nm.
        """
        info = {}
        for meas in cls._iter(root, 'xrdMeasurement', ns):
            wl = cls._find(meas, 'usedWavelength', ns)
            if wl is not None:
                kA1   = cls._text(wl, 'kAlpha1', ns)
                kA2   = cls._text(wl, 'kAlpha2', ns)
                kB    = cls._text(wl, 'kBeta', ns)
                ratio = cls._text(wl, 'ratioKAlpha2KAlpha1', ns)
                if kA1:
                    info['alpha1'] = float(kA1) / 10.0
                if kA2:
                    info['alpha2'] = float(kA2) / 10.0
                if kB:
                    info['beta'] = float(kB) / 10.0
                # Weighted average: (kA1 + ratio*kA2) / (1 + ratio)
                if kA1 and kA2 and ratio:
                    r = float(ratio)
                    info['alpha_average'] = (float(kA1) + r * float(kA2)) / (1.0 + r) / 10.0
                elif kA1:
                    info['alpha_average'] = float(kA1) / 10.0
            break
        return info

    @classmethod
    def _get_sample_name(cls, root, ns, basename):
        """Return the sample name from the XML or fall back to the filename stem."""
        for meas in cls._iter(root, 'xrdMeasurement', ns):
            sid = cls._text(meas, 'sampleID', ns)
            if sid:
                return sid
            # Some files use comment as a label
            comment = cls._text(meas, 'comment', ns)
            if comment:
                return comment
            break
        # Fall back to filename without extension
        if basename:
            return os.path.splitext(basename)[0]
        return "Unknown"

    # ------------------------------------------------------------------
    #   Scan parsing
    # ------------------------------------------------------------------

    @classmethod
    def _parse_datapoints(cls, dp, ns):
        """
        Parse a single <dataPoints> element.
        Returns (two_theta_array, intensity_array) or None.
        Intensities are normalised to counts-per-second.
        """
        # --- 2theta positions ---
        two_theta = None
        start_pos = end_pos = None

        for pos in cls._iter(dp, 'positions', ns):
            if pos.get('axis') == '2Theta':
                # Explicit list (variable step)
                lp = cls._find(pos, 'listPositions', ns)
                if lp is not None and lp.text:
                    two_theta = np.fromstring(lp.text, dtype=float, sep=' ')
                    break
                # Fixed step: start/end range, reconstruct with linspace
                s_el = cls._find(pos, 'startPosition', ns)
                e_el = cls._find(pos, 'endPosition', ns)
                if s_el is not None and e_el is not None:
                    start_pos = float(s_el.text)
                    end_pos   = float(e_el.text)
                break

        # --- counting time ---
        ct_el = cls._find(dp, 'commonCountingTime', ns)
        count_time = float(ct_el.text) if (ct_el is not None and ct_el.text) else 1.0

        # --- intensities ---
        int_el = cls._find(dp, 'intensities', ns)
        if int_el is None:
            int_el = cls._find(dp, 'counts', ns)
        if int_el is None or not int_el.text:
            return None

        intensity_unit = (int_el.get('unit', 'counts') if int_el is not None else 'counts')
        intensity_raw = np.fromstring(int_el.text, dtype=float, sep=' ')
        n = len(intensity_raw)
        if n == 0:
            return None

        # Build 2theta array if we only have start/end
        if two_theta is None:
            if start_pos is None:
                return None
            two_theta = np.linspace(start_pos, end_pos, n)

        # Normalise to CPS unless already in CPS
        if intensity_unit.lower() in ('counts', 'counts per step', ''):
            intensity = intensity_raw / count_time
        else:
            intensity = intensity_raw  # already CPS

        if len(two_theta) != len(intensity):
            # Mismatch — truncate to shorter
            m = min(len(two_theta), len(intensity))
            two_theta = two_theta[:m]
            intensity = intensity[:m]

        return two_theta, intensity

    # ------------------------------------------------------------------
    #   Main parse entry point
    # ------------------------------------------------------------------

    @classmethod
    def parse(cls, fp, data_objects=None, close=True):
        filename, fp, close = cls._get_file(fp, close=close)

        try:
            basename = os.path.basename(filename) if filename else None
        except (AttributeError, TypeError):
            basename = None

        data_objects = not_none(data_objects, [])

        _, root = cls.get_xml_for_file(fp)
        ns = cls._get_ns(root)

        wavelength_info = cls._parse_wavelength(root, ns)
        sample_name     = cls._get_sample_name(root, ns, basename)

        num_samples = 0

        for meas in cls._iter(root, 'xrdMeasurement', ns):
            for scan in cls._iter(meas, 'scan', ns):
                # Skip incomplete scans
                if scan.get('status', '') == 'Aborted':
                    continue

                for dp in cls._iter(scan, 'dataPoints', ns):
                    result = cls._parse_datapoints(dp, ns)
                    if result is None:
                        continue

                    two_theta, intensity = result
                    if len(two_theta) == 0:
                        continue

                    # Extend data_objects list as needed
                    data_objects = cls._adapt_data_object_list(
                        data_objects,
                        num_samples=(num_samples + 1),
                        only_extend=True
                    )
                    data_object = data_objects[num_samples]

                    data_object.update(
                        filename=basename,
                        name=sample_name,
                        twotheta_min=float(two_theta[0]),
                        twotheta_max=float(two_theta[-1]),
                        twotheta_count=int(len(two_theta)),
                        twotheta_step=float(
                            (two_theta[-1] - two_theta[0]) / max(len(two_theta) - 1, 1)
                        ),
                        **wavelength_info
                    )
                    data_object.data = list(zip(two_theta.tolist(), intensity.tolist()))

                    num_samples += 1

        if close:
            fp.close()
        return data_objects

    pass  # end of class
